import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"67. Pre Adoption Leave","description":"","frontmatter":{"title":"67. Pre Adoption Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","parental-leave","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/67-pre-adoption-leave.md","filePath":"ebas/nurses-midwives/leave/67-pre-adoption-leave.md"}'),r={name:"ebas/nurses-midwives/leave/67-pre-adoption-leave.md"};function i(p,e,s,l,d,v){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_67-pre-adoption-leave" tabindex="-1">67. Pre Adoption Leave <a class="header-anchor" href="#_67-pre-adoption-leave" aria-label="Permalink to &quot;67. Pre Adoption Leave&quot;">​</a></h1><p><strong>67.1</strong> An Employee seeking to adopt a child is entitled to unpaid leave for the purpose of attending any compulsory interviews or examinations as are necessary as part of the Adoption procedure.</p><p><strong>67.2</strong> The Employee and the Employer should agree on the length of the unpaid leave.</p><p><strong>67.3</strong> Where agreement cannot be reached, the Employee is entitled to take up to two days&#39; unpaid leave.</p><p><strong>67.4</strong> Where paid leave is available to the Employee, the Employer may require the Employee to take such leave instead.</p><p>Plain language terms: adoption leave, adopting a child.</p>',6)])])}const c=a(r,[["render",i]]);export{h as __pageData,c as default};
